var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"つまり……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여긴 침식체 뱃속이라는 거죠?","JPN":"ここは侵食体のお腹の中ってことですよね？","ENG":"We're inside the C.O.'s belly?","TWN":"我們在侵蝕體的肚子裡，對吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하. 정확하시네요. 소화되지 않은 것만 해도 다행이죠?","JPN":"あはは、その通りです。消化されていないだけでも幸運ですよ。","ENG":"Ah hah hah. That's correct. Aren't you glad you weren't digested?","TWN":"呵呵呵，猜對囉。沒被消化掉算是不幸中的大幸吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"다행…… ","JPN":"幸運…… ","ENG":"Glad...?","TWN":"不幸中的……大幸？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"은 아니죠!","JPN":"そんなわけないでしょ！","ENG":"As if!","TWN":"才不是！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼 천천히 죽기랑 빨리 죽기 중에 선택하라는 것 아니에요?","JPN":"結局ゆっくり死んでいくか、すぐに死んでしまうかのどちらかを選ぶしかないじゃないですか。","ENG":"Then, we're forced to choose between a quick or a slow death!","TWN":"那不就是要在快點死和慢點死裡面選一個嗎！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"보기보단 똑똑한 분이시군요.","JPN":"案外鋭いですね。","ENG":"You're smarter than you look.","TWN":"沒想到你蠻聰明的嘛。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇게 빨리 인정하지 마세요! 그럼 당신은 뭔데 여기 있는 건데요?","JPN":"そんなにあっさりと認めないでください！　じゃあ、あなたは誰で、どうしてここにいるんですか？","ENG":"Don't be so quick to admit it! Then what are you doing here?","TWN":"不要那麼快承認！那你又是什麼人，為什麼在這裡？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 그림자인 거지!","JPN":"やっぱりシャドウなんだ！","ENG":"I knew it! You are a Shadow!","TWN":"果然是暗影吧！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"그럼 여기, 제 워치를 보여드릴게요.","JPN":"じゃあこれ、私のウォッチを見てください。","ENG":"Here, I'll show you my Watch, then.","TWN":"你看，這是我的能量環。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"자, 여기 아직 초침이 움직이는 게 보이시나요?","JPN":"はい、まだ針が動いているのが見えますか？","ENG":"Look. See how that second hand is still moving?","TWN":"你還能看到秒針在動吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……일단 그림자가 아닐 수도 있다는 가능성을 염두에 둘게요.","JPN":"……まぁ、とりあえず、シャドウじゃない可能性は念頭に置いておきます。","ENG":"...I'll keep note that you might not be a Shadow, then.","TWN":"……我會考慮你不是暗影的可能性。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하. 냉정하셔라. 그럼 이제 여길 빠져나가지 못한 이유도 설명해 드려야겠죠?","JPN":"あはは、冷静ですね。では、私がどうしてここから脱出できていないのかもお話しますね。","ENG":"Ah hah hah. How calm. Now, I should explain why I haven't been able to get out of here as well.","TWN":"呵呵呵，真是冷靜。那麼我還得解釋下為什麼沒能離開這裡的原因吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"여기, 지팡이 위로 뜬 홀로그램에서 계속 좌표가 변하는 게 보이세요?","JPN":"この、杖が出しているホログラムの座標が変化し続けているのがわかりますか？","ENG":"Here. Do you see how the coordinates that appear on the hologram above the staff keep changing?","TWN":"這裡，我這杖上的全息圖，裡面的座標在不斷地變化，你有看到吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"이 침식체는 허수 공간과 현실 세계를 헤엄치는 특징이 있어요.","JPN":"この侵食体は、虚数空間と現実世界の狭間を泳ぐかのように、行き来することが特徴です。","ENG":"This C.O.'s nature is swimming in both the imaginary space and the Normalside.","TWN":"這個侵蝕體的特色，就是會在虛數空間和現實世界之間遊走。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"허수 공간은 시시각각 좌표가 왜곡되는데, 그건 이 침식체의 내부에도 영향을 끼치죠.","JPN":"虚数空間は座標が常に歪み続けており、それはこの侵食体の身体の内部にも影響を及ぼします。","ENG":"The imaginary space continuously distorts the coordinates, which also affects the inside of the C.O.","TWN":"虛數空間中的座標時刻在扭曲，也會影響到侵蝕體的內部。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"계속해서 같은 곳으로 나온다든가, 출구가 어느 날 막혀 있다든가 하는 일들이 일어나요.","JPN":"ずっと同じところをぐるぐる回ったり、出口が塞がっていたリ、そのようなことの繰り返しです。","ENG":"Odd things happen, like returning to the same place over again, or having the exit blocked one day.","TWN":"常常會發生奇怪的事，比如總是從同一個地方出來，或者某天出口被堵住之類的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"흠…… 진실인지 아닌지는 확인해 봐야 알겠어요.","JPN":"うーん……それが本当かどうかは、自分で見るまではなんとも言えませんね。","ENG":"Hmm... I need to see if what you say is true or not.","TWN":"嗯……是真是假，還得確認一下才知道。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"이런 곳일수록 의심이 많은 게 좋죠. 그래야 살 확률이 올라가는 법이니까요.","JPN":"疑うことは、こういう場所では大切です。生存率を高めてくれますからね。","ENG":"It's better to be skeptical when you're in a place like this. It only increases your odds of survival.","TWN":"在這種地方多疑是好事，這樣才能提高生存幾率。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"어쩌다가 여기 오게 되신 거예요? 현실에 오래 머무르는 침식체가 아닌데.","JPN":"どうしてここに来ることになったのですか？　現実世界に長く出現するような侵食体ではないのですが。","ENG":"How did you get here? This C.O. doesn't really stay on the Normalside for that long.","TWN":"不過你是怎麼來到這裡的？這個侵蝕體是不會長時間停留在現世中的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"습격을 당했어요.","JPN":"奇襲を受けてしまったんです。","ENG":"We were attacked.","TWN":"我們遭到它的攻擊。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저와 함께하던 카운터께서 어떻게든 이 침식체를 막아내려고 했지만…….","JPN":"私と一緒にいたカウンター様が、こいつと戦ってくれましたが……","ENG":"The Counter I was with tried to stop it, but...","TWN":"和我一起的制裁者想盡辦法要阻止它，但是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 다치는 바람에 제대로 싸우지 못하셨죠.","JPN":"私が怪我をしたせいで、思うように戦うことができなくなってしまって。","ENG":"I got wounded and she couldn't fight properly because of that.","TWN":"後來因為我受傷，害她無法繼續戰鬥。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 나서 제가 먹혔으니, 어쩌면 그분도 여기 계실 수도 있겠어요.","JPN":"そのあと私は食べられてしまったので、もしかしたらその方もここにいらっしゃるかもしれません。","ENG":"And since I've been swallowed by it, maybe she's also somewhere around here.","TWN":"然後我就被這個侵蝕體吞掉了，或許她也在這裡面。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}}]`);export{e as default};